#include<bits/stdc++.h>
using namespace std;
long long b[200010];
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long vl,vr,maxr,maxl,ans,len,rev_tag;
    }t[600010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(node &x,node ls,node rs)
    {
    	x.vl=ls.vl;
    	x.vr=rs.vr;
    	x.len=ls.len+rs.len;
    	int llen=ls.len,rlen=rs.len;
		if(ls.vr!=rs.vl)
		{
			x.maxl=(ls.maxl==llen?llen+rs.maxl:ls.maxl);
			x.maxr=(rs.maxr==rlen?rlen+ls.maxr:rs.maxr);
			x.ans=ls.ans+rs.ans+(ls.maxr*rs.maxl);
		}
		else
		{
			x.maxl=ls.maxl;
			x.maxr=rs.maxr;
        	x.ans=ls.ans+rs.ans;
		}
    }
    void pushup(long long x)
    {
        pushup(t[x],t[t[x].lson],t[t[x].rson]);
    }
    void pushrev(long long x)
    {
    	t[x].vl^=1;
    	t[x].vr^=1;
    	t[x].rev_tag^=1;
	}
	void pushdown(long long x)
	{
		if(t[x].rev_tag)
		{
			pushrev(t[x].lson);
			pushrev(t[x].rson);
			t[x].rev_tag=0;
		}
	}
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        t[x].l=l;
        t[x].r=r;
        t[x].lson=t[x].rson=0;
        t[x].rev_tag=0;
        if(l==r)
        {
            t[x].vl=t[x].vr=b[l];
            t[x].maxl=t[x].maxr=1;
            t[x].ans=1;
            t[x].len=1;
            return x;
        }
        long long mid=(l+r)>>1;
        t[x].lson=init(l,mid);
        t[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long l,long long r)
    {
    	if(t[x].l>r||t[x].r<l)
    	{
    		return;
		}
		if(l<=t[x].l&&t[x].r<=r)
		{
			pushrev(x);
			return;
		}
		pushdown(x);
		update(t[x].lson,l,r);
		update(t[x].rson,l,r);
		pushup(x);
	}
    node query(long long x,long long l,long long r)
    {
        if(l<=t[x].l&&t[x].r<=r)
        {
            return t[x];
        }
        pushdown(x);
        long long mid=(t[x].l+t[x].r)>>1;
        if(l<=mid&&r>mid)
        {
            node ans=t[x];
            pushup(ans,query(t[x].lson,l,r),query(t[x].rson,l,r));
            return ans;
        }
        else if(l<=mid)
        {
            return query(t[x].lson,l,r);
        }
        else
        {
            return query(t[x].rson,l,r);
        }
    }
}t;
int main()
{
	long long n,q;
	scanf("%lld%lld",&n,&q);
	for(long long i=1;i<=n;i++)
	{
		scanf("%lld",&b[i]);	
	}
	t.init(1,n);
	while(q--)
	{
		long long op,x,y;
		scanf("%lld%lld%lld",&op,&x,&y);
		if(op==1)
		{
			t.update(1,x,y);
		}
		else
		{
			segment_tree::node p=t.query(1,x,y);
			printf("%lld\n",p.ans);
		}
	}
	return 0;
}
